queries.sphinxql:
DROP TABLE IF EXISTS rt;
CREATE TABLE rt (title text, category integer, name_rank integer);
INSERT INTO rt (id, title, category, name_rank) VALUES
(1, 'one', 7, 4), (2, 'two', 7, 1), (3, 'three', 7, 3), (4, 'four', 7, 2),
(5, 'five', 8, 2), (6, 'six', 8, 1),
(7, 'seven', 9, 1), (8, 'eight', 9, 1), (9, 'nine', 9, 2);


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 3) AS ids FROM rt GROUP BY category ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank, id LIMIT 99) AS ids FROM rt GROUP BY category ORDER BY category ASC;


SELECT category,
	GROUP_CONCAT( id   ORDER BY `name_rank` , `id` DESC LIMIT 2 ) AS ids
FROM rt GROUP BY category ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank LIMIT 0) AS ids FROM rt GROUP BY category ORDER BY category ASC;


SELECT category, id, GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 3) AS ids FROM rt GROUP 2 BY category WITHIN GROUP ORDER BY id DESC ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id) AS all_ids, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS first_ids FROM rt GROUP BY category ORDER BY category ASC OPTION threads=1;


SELECT category,
	GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 1) AS first_id,
	GROUP_CONCAT(id ORDER BY id DESC LIMIT 2) AS last_ids
FROM rt GROUP BY category ORDER BY category ASC;


SELECT category, id, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP 2 BY category WITHIN GROUP ORDER BY id ASC ORDER BY category ASC;


SELECT category, COUNT(*) AS n, GROUP_CONCAT(id ORDER BY id ASC LIMIT 1) AS first_id
FROM rt GROUP BY category ORDER BY n DESC, category ASC;


SELECT category, COUNT(*) AS n, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category HAVING n>=3 ORDER BY category ASC;


SELECT category, MIN(name_rank-name_rank) AS z,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category ORDER BY z ASC OPTION max_matches=2;


SELECT category,
	MIN(id) AS a1, MAX(id) AS a2, SUM(id) AS a3, AVG(id) AS a4,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category ORDER BY a1 ASC, a2 ASC, a3 ASC, a4 ASC, `category` ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC, id DESC LIMIT 3) AS ids
FROM rt GROUP BY category ORDER BY category ASC OPTION threads=4;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 3) AS ids
FROM rt GROUP BY category ORDER BY category ASC OPTION max_matches=3;
SHOW META;


SELECT category,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS `@group_concat_value_0`
FROM rt GROUP BY category ORDER BY category ASC;


SELECT GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category ORDER BY `ids` ASC;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category HAVING ids='2,4';
SELECT category, id, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category ORDER BY id ASC;

SELECT category, GROUP_CONCAT(id ORDER BY missing_order ASC LIMIT 2) AS ids
FROM rt GROUP BY category ORDER BY category ASC;
SELECT category,
	MIN(id) AS a1, MAX(id) AS a2, SUM(id) AS a3, AVG(id) AS a4, COUNT(*) AS a5,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category ORDER BY a1 ASC, a2 ASC, a3 ASC, a4 ASC, a5 ASC;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2147483647) AS ids FROM rt GROUP BY category ORDER BY category ASC;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT -1) AS ids FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2147483648) AS ids FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(DISTINCT id ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(id, category ORDER BY name_rank ASC LIMIT 2) AS ids FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2 SEPARATOR ':') AS ids FROM rt GROUP BY category;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2 OFFSET 1) AS ids FROM rt GROUP BY category;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category FACET category;
SELECT * FROM (
	SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
	FROM rt GROUP BY category
) ORDER BY category ASC;
SELECT REMOVE_REPEATS((
	SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
	FROM rt GROUP BY category ORDER BY category ASC
), category, 0, 10);
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt WHERE KNN(embedding,3,(1.0,2.0,3.0)) GROUP BY category;
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 2) AS ids
FROM rt GROUP BY category ORDER BY category ASC, id DESC LIMIT 2
OPTION scroll='eyJvcmRlcl9ieV9zdHIiOiJjYXRlZ29yeSBhc2MsIGlkIGRlc2MiLCJvcmRlcl9ieSI6W3siYXR0ciI6ImNhdGVnb3J5IiwiZGVzYyI6ZmFsc2UsInZhbHVlIjo3LCJ0eXBlIjoiaW50In0seyJhdHRyIjoiaWQiLCJkZXNjIjp0cnVlLCJ2YWx1ZSI6OSwidHlwZSI6ImludCJ9XX0=';

DROP TABLE IF EXISTS rt_join;
CREATE TABLE rt_join (title text, category integer);
SELECT rt.category, GROUP_CONCAT(rt.id ORDER BY rt.name_rank ASC LIMIT 2) AS ids
FROM rt LEFT JOIN rt_join ON rt.id=rt_join.id GROUP BY rt.category;
DROP TABLE rt_join;

DROP TABLE rt;

DROP TABLE IF EXISTS rt_rowwise;
CREATE TABLE rt_rowwise (title text, category integer, name_rank integer, label string attribute);
INSERT INTO rt_rowwise (id, title, category, name_rank, label) VALUES
(1, 'one', 7, 1, 'one'), (2, 'two', 7, 2, 'two'), (3, 'three', 7, 3, 'three'), (4, 'four', 7, 4, 'four');
FLUSH RAMCHUNK rt_rowwise;
SELECT category, GROUP_CONCAT(CONCAT(label, ':', TO_STRING(id)) ORDER BY name_rank DESC LIMIT 3) AS labels
FROM rt_rowwise GROUP BY category;
DROP TABLE rt_rowwise;

DROP TABLE IF EXISTS rt_columnar_chunks;
CREATE TABLE rt_columnar_chunks (title text, category integer, name_rank integer, label string attribute) engine='columnar';
INSERT INTO rt_columnar_chunks (id, title, category, name_rank, label) VALUES
(1, 'one', 7, 1, 'one'), (2, 'two', 7, 2, 'two');
FLUSH RAMCHUNK rt_columnar_chunks;
INSERT INTO rt_columnar_chunks (id, title, category, name_rank, label) VALUES
(3, 'three', 7, 3, 'three'), (4, 'four', 7, 4, 'four');
FLUSH RAMCHUNK rt_columnar_chunks;
SELECT category, GROUP_CONCAT(CONCAT(label, ':', TO_STRING(id)) ORDER BY name_rank ASC LIMIT 4) AS labels
FROM rt_columnar_chunks GROUP BY category OPTION threads=4;
SELECT category, GROUP_CONCAT(CONCAT(label, '') ORDER BY name_rank ASC LIMIT 0) AS label
FROM rt_columnar_chunks GROUP BY category;
DROP TABLE rt_columnar_chunks;

DROP TABLE IF EXISTS rt_remote_odd;
CREATE TABLE rt_remote_odd (title text, category integer, name_rank integer, label string attribute);
INSERT INTO rt_remote_odd (id, title, category, name_rank, label) VALUES
(1, 'one', 7, 1, 'odd-1'), (3, 'three', 7, 3, 'odd-3'), (5, 'five', 7, 5, 'odd-5'),
(7, 'seven', 8, 1, 'odd-7'), (9, 'nine', 8, 3, 'odd-9');

DROP TABLE IF EXISTS rt_remote_even;
CREATE TABLE rt_remote_even (title text, category integer, name_rank integer, label string attribute);
INSERT INTO rt_remote_even (id, title, category, name_rank, label) VALUES
(2, 'two', 7, 2, 'even-2'), (4, 'four', 7, 4, 'even-4'), (6, 'six', 7, 6, 'even-6'),
(8, 'eight', 8, 2, 'even-8'), (10, 'ten', 8, 4, 'even-10');

DROP TABLE IF EXISTS rt_remote_dist;
CREATE TABLE rt_remote_dist type='distributed'
agent=':rt_remote_odd'
agent=':rt_remote_even';


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 4) AS ids
FROM rt_remote_dist GROUP BY category ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 4) AS ids
FROM rt_remote_dist GROUP BY category ORDER BY category ASC OPTION max_matches=2;
SHOW META;


SELECT category, GROUP_CONCAT(id) AS ids
FROM rt_remote_dist GROUP BY category ORDER BY category ASC OPTION threads=1;


SELECT category, id, GROUP_CONCAT(id) AS ids
FROM rt_remote_dist GROUP 2 BY category WITHIN GROUP ORDER BY id DESC ORDER BY category ASC OPTION threads=1;


SELECT category,
	GROUP_CONCAT(id) AS all_ids,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 3) AS first_ids,
	GROUP_CONCAT(id ORDER BY id DESC LIMIT 2) AS last_ids
FROM rt_remote_dist GROUP BY category ORDER BY category ASC OPTION threads=1;


SELECT category,
	GROUP_CONCAT(CONCAT(label, ':', TO_STRING(id)) ORDER BY name_rank DESC LIMIT 3) AS labels
FROM rt_remote_dist GROUP BY category ORDER BY category ASC;


SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 4) AS ids
FROM rt_remote_dist GROUP BY category ORDER BY category ASC LIMIT 1;


SELECT category,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 3) AS first_ids,
	GROUP_CONCAT(label ORDER BY id DESC LIMIT 2) AS labels
FROM rt_remote_dist GROUP BY category ORDER BY category ASC OPTION threads=4;
SELECT category,
	GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 3) AS first_ids,
	GROUP_CONCAT(label ORDER BY id DESC LIMIT 2) AS labels
FROM rt_remote_dist GROUP BY category ORDER BY category ASC OPTION threads=4;


DROP TABLE IF EXISTS rt_remote_refused;
CREATE TABLE rt_remote_refused type='distributed'
agent=':rt_remote_odd'
agent='127.0.0.1:1:rt_remote_even';
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 3) AS ids
FROM rt_remote_refused GROUP BY category ORDER BY category ASC;
SHOW WARNINGS;
DROP TABLE rt_remote_refused;

DROP TABLE rt_remote_dist;

DROP TABLE IF EXISTS rt_local_a;
DROP TABLE IF EXISTS rt_local_b;
DROP TABLE IF EXISTS rt_local_dist;
CREATE TABLE rt_local_a (title text, category integer, name_rank integer);
CREATE TABLE rt_local_b (title text, category integer, name_rank integer);
INSERT INTO rt_local_a (id, title, category, name_rank) VALUES
(1, 'one', 7, 1), (3, 'three', 7, 3), (5, 'five', 7, 5);
INSERT INTO rt_local_b (id, title, category, name_rank) VALUES
(2, 'two', 7, 2), (4, 'four', 7, 4), (6, 'six', 7, 6);
CREATE TABLE rt_local_dist type='distributed' local='rt_local_a' local='rt_local_b';
SELECT category, GROUP_CONCAT(id ORDER BY name_rank ASC LIMIT 4) AS ids
FROM rt_local_dist GROUP BY category;
